    "privacy_right_access": "Derecho de Acceso",
    "privacy_right_access_desc": "Tienes derecho a obtener confirmación de si tus datos se procesan y a acceder a esos datos.",
    "privacy_right_rectification": "Derecho de Rectificación",
    "privacy_right_rectification_desc": "Puedes solicitar la corrección de datos personales inexactos que te conciernen.",
    "privacy_right_erasure": "Derecho al Olvido",
    "privacy_right_erasure_desc": "Puedes solicitar la eliminación de tus datos personales en ciertas circunstancias.",
    "privacy_right_portability": "Derecho a la Portabilidad de Datos",
    "privacy_right_portability_desc": "Tienes derecho a recibir tus datos en un formato estructurado, de uso común y legible por máquina.",
